import{c as a,Q as o,j as t,m as l}from"./chunks/framework.CdiUUa3G.js";const f=JSON.parse('{"title":"ADR-044 — CJK font strategy for Wave 2 locales","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-044.md","filePath":"adr/ADR-044.md"}'),n={name:"adr/ADR-044.md"};function i(r,e,s,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="adr-044-—-cjk-font-strategy-for-wave-2-locales" tabindex="-1">ADR-044 — CJK font strategy for Wave 2 locales <a class="header-anchor" href="#adr-044-—-cjk-font-strategy-for-wave-2-locales" aria-label="Permalink to &quot;ADR-044 — CJK font strategy for Wave 2 locales&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-06 Supersedes in part · <code>docs/adr/ADR-032.md</code> (Wave 2 CJK deferred note) Scope · <code>zh-CN</code>, <code>ja</code>, <code>ko</code></p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Issue #37 schedules Wave 2 locale rollout for Simplified Chinese (<code>zh-CN</code>), Japanese (<code>ja</code>), and Korean (<code>ko</code>). ADR-032 explicitly deferred the CJK font decision.</p><p>We need a decision that keeps bundle risk low while ensuring CJK glyph coverage does not regress readability.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>For Wave 2, Orrery keeps its existing bundled typography and relies on platform font fallback for CJK glyph rendering.</p><p>No new bundled CJK font files are added in this rollout.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Avoids adding large CJK font payloads to every user&#39;s first paint.</li><li>Preserves current visual identity (<code>Bebas Neue</code>, <code>Space Mono</code>, <code>Crimson Pro</code>) where those fonts already apply.</li><li>Keeps Wave 2 implementation minimally invasive: locale plumbing and content overlays only.</li><li>Matches ADR-017 fallback behavior and current static-site delivery constraints.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li>Zero additional font bytes for non-CJK users.</li><li>No changes required to asset fetch/preload pipeline.</li><li>Wave 2 can ship immediately with low operational risk.</li></ul><p>Negative:</p><ul><li>Typography can vary by OS/browser for CJK text because fallback stacks differ.</li><li>Some headings may show mixed-font appearance when branded fonts lack CJK glyphs.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Bundle per-locale Noto Sans fonts (SC/JP/KR):</strong> improves consistency, but adds significant payload and font-loading complexity.</li><li><strong>Bundle a single Noto Sans CJK family:</strong> one strategy for all CJK locales, but still large and costly for non-CJK traffic.</li><li><strong>Delay Wave 2 until dedicated CJK font pipeline lands:</strong> rejected; blocks locale rollout on non-critical styling work.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Add Wave 2 locales to <code>project.inlang/settings.json</code>, runtime locale lists, messages, and data overlays.</li><li>Keep <code>?lang=</code> as locale source-of-truth; no storage-based locale state.</li><li>If future UX requires stronger cross-platform CJK consistency, supersede with a dedicated font-loading ADR.</li></ul>',19)])])}const h=a(n,[["render",i]]);export{f as __pageData,h as default};
